export class TxMsgBurnNonFungible {
    constructor(init) {
        this.tokenId = 0n;
        this.instanceId = 0n;
        Object.assign(this, init);
    }
    write(w) {
        w.write8u(this.tokenId);
        w.write8u(this.instanceId);
    }
    read(r) {
        this.tokenId = r.read8u();
        this.instanceId = r.read8u();
    }
    static read(r) {
        const v = new TxMsgBurnNonFungible();
        v.read(r);
        return v;
    }
}
